DROP TABLE IF EXISTS `usedcar`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `usedcar` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `addtime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `brand` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '品牌',
  `model1` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '型号',
  `discountprice` double DEFAULT NULL COMMENT '现价',
  `originalprice` double DEFAULT NULL COMMENT '已减',
  `vehicleage` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '年份',
  `kilometer` double DEFAULT NULL COMMENT '行驶里程',
  `imgurl` longtext COLLATE utf8mb4_unicode_ci COMMENT '图片',
  `xqurl` longtext COLLATE utf8mb4_unicode_ci COMMENT '链接',
  `city` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所在城市',
  `thumbsupnum` int(11) DEFAULT '0' COMMENT '赞',
  `crazilynum` int(11) DEFAULT '0' COMMENT '踩',
  `clicktime` datetime DEFAULT NULL COMMENT '最近点击时间',
  `clicknum` int(11) DEFAULT '0' COMMENT '点击次数',
  `discussnum` int(11) DEFAULT '0' COMMENT '评论数',
  `storeupnum` int(11) DEFAULT '0' COMMENT '收藏数',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=10061 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='二手车';
